{"type":"message","id":"c9afbdeb","parentId":"84ca175a","timestamp":"2026-03-19T17:00:55.380Z","message":{"role":"assistant","content":[{"type":"toolCall","id":"ollama_call_7db3824b-b096-49fa-a4f2-72d5bcc15b3a","name":"write","arguments":{"content":"#!/usr/bin/env python3\n\"\"\"\nAbroadWorks Vector RAG Query - Simple semantic search\nUsage: python query_vector.py \"your question\"\n\"\"\"\n\nimport json\nimport math\nimport sys\nfrom pathlib import Path\nfrom collections import Counter\nimport hashlib\n\nROOT = Path('/home/tiny4lurv/.openclaw/workspace')\nINDEX_FILE = ROOT / 'rag_abroadworks' / 'index' / 'vector_index.json'\n\nFALLBACK_DIMS = 768\n\ndef tokenize(text):\n    import re\n    TOKEN_RE = re.compile(r\"[a-zA-Z][a-zA-Z0-9\\-]{1,}\")\n    return [t.lower() for t in TOKEN_RE.findall(text)]\n\ndef hash_feature(s, dims):\n    h = hashlib.sha1(s.encode('utf-8')).digest()\n    idx = int.from_bytes(h[:4], 'big') % dims\n    sign = 1.0 if (h[4] & 1) == 0 else -1.0\n    return idx, sign\n\ndef l2_normalize(v):\n    norm = math.sqrt(sum(x * x for x in v))\n    if norm == 0:\n        return v\n    return [x / norm for x in v]\n\ndef build_fallback_vector(query, dims=384):\n    toks = tokenize(query)\n    tf = Counter(toks)\n    vec = [0.0] * dims\n    for tok, freq in tf.items():\n        w = 1.0 + math.log(freq)\n        idx, sign = hash_feature(f\"tok::{tok}\", dims)\n        vec[idx] += sign * w\n    return l2_normalize(vec)\n\ndef cosine_similarity(a, b):\n    return sum(x * y for x, y in zip(a, b))\n\ndef main():\n    if len(sys.argv) < 2:\n        print(\"Usage: python query_vector.py \\\"your question\\\"\")\n        sys.exit(1)\n    \n    query = \" \".join(sys.argv[1:])\n    \n    # Load index\n    with open(INDEX_FILE) as f:\n        data = json.load(f)\n    \n    docs = data['docs']\n    vectors = data['vectors']\n    \n    print(f\"Query: {query}\")\n    print(f\"Backend: {data['meta'].get('backend', 'unknown')}\")\n    print(f\"Searching {len(docs)} docs...\\n\")\n    print(\"=\" * 50)\n    \n    # Build query vector (try fastembed, fallback to hash)\n    try:\n        from fastembed import TextEmbedding\n        model = TextEmbedding(model_name=\"BAAI/bge-small-en-v1.5\")\n        query_vec = list(model.embed([query]))[0].tolist()\n        query_vec = l2_normalize(query_vec)\n        backend = \"fastembed\"\n    except Exception as e:\n        print(f\"Note: Using fallback vector (fastembed unavailable: {e})\")\n        query_vec = build_fallback_vector(query, 384)\n        backend = \"fallback\"\n    \n    # Score all docs\n    scores = []\n    for i, (doc, vec) in enumerate(zip(docs, vectors)):\n        score = cosine_similarity(query_vec, vec)\n        scores.append((score, doc))\n    \n    # Sort by score\n    scores.sort(key=lambda x: x[0], reverse=True)\n    \n    # Print top 5\n    for rank, (score, doc) in enumerate(scores[:5], 1):\n        print(f\"\\n[{rank}] {doc.get('title', 'Unknown')}\")\n        print(f\"    Score: {score:.4f}\")\n        print(f\"    Source: {doc.get('url', doc.get('source', 'N/A'))}\")\n        text = doc.get('text', '')[:250]\n        print(f\"    {text}...\")\n\nif __name__ == \"__main__\":\n    main()","path":"/home/tiny4lurv/.openclaw/workspace/rag_abroadworks/query_vector.py"}}],"stopReason":"toolUse","api":"ollama","provider":"ollama","model":"minimax-m2.5:cloud","usage":{"input":60524,"output":913,"cacheRead":0,"cacheWrite":0,"totalTokens":61437,"cost":{"input":0,"output":0,"cacheRead":0,"cacheWrite":0,"total":0}},"timestamp":1773939655379}}
